//! C emit — translates the validated `Registry` into GBDK-compatible C tables.

use std::fs;
use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use quintra_content::{
    AiScriptId, BaseStats, Class, DoorMask, Effect, Enemy, EnemyStats, FormTheme,
    Item, ItemKind, ProjectileKind, Rarity, Registry, RoomKind, RoomSize, RoomTemplate,
    ScreenCellKind, ShotPattern, SpawnRole, SpawnSlot, Status, Stat, Trigger,
    ZeldaOverworldBiome,
};

const HEADER_NOTE: &str =
    "// AUTO-GENERATED BY quintra-codegen — DO NOT EDIT BY HAND.\n\
     // Source: content/src/. Regenerate via `cargo run -p quintra-codegen`.\n\n";

pub fn write_all(out: &Path, reg: &Registry) -> Result<()> {
    write_enums(out)?;
    write_classes(out, reg)?;
    write_items(out, reg)?;
    write_enemies(out, reg)?;
    write_biomes(out, reg)?;
    write_zelda_overworld(out, reg)?;
    write_rooms(out, reg)?;
    write_stages(out, reg)?;
    write_umbrella(out, reg)?;
    Ok(())
}

// ---------------------------------------------------------------- enums

