// ---------------------------------------------------------------- classes

fn write_classes(out: &Path, reg: &Registry) -> Result<()> {
    let mut header = String::from(HEADER_NOTE);
    header.push_str(
        "#ifndef QUINTRA_GEN_CLASSES_H\n\
         #define QUINTRA_GEN_CLASSES_H\n\
         #include \"core/types.h\"\n\
         #include \"enums.h\"\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u8 hp_max;\n\
         \x20\x20\x20\x20u8 mp_max;\n\
         \x20\x20\x20\x20u8 atk;\n\
         \x20\x20\x20\x20u8 def;\n\
         \x20\x20\x20\x20u8 spd;\n\
         } base_stats_t;\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u8           id;\n\
         \x20\x20\x20\x20const char*  name;\n\
         \x20\x20\x20\x20u8           form_theme;\n\
         \x20\x20\x20\x20u8           palette;\n\
         \x20\x20\x20\x20u8           sprite_set;\n\
         \x20\x20\x20\x20u16          starter_weapon;\n\
         \x20\x20\x20\x20u16          signature_active;\n\
         \x20\x20\x20\x20u8           passive_perk;\n\
         \x20\x20\x20\x20base_stats_t base_stats;\n\
         } class_def_t;\n\
         \n",
    );
    header.push_str(&format!("#define N_CLASSES {}\n", reg.n_classes()));
    header.push_str("extern const class_def_t classes[];\n#endif\n");
    write_if_changed(out.join("classes.h"), header)?;

    let mut body = String::from(HEADER_NOTE);
    body.push_str("#include \"classes.h\"\n\nconst class_def_t classes[] = {\n");
    for c in &reg.classes { body.push_str(&emit_class(c)); }
    body.push_str("};\n");
    write_if_changed(out.join("classes.c"), body)?;
    Ok(())
}

fn emit_class(c: &Class) -> String {
    format!(
        "    {{ .id={}, .name=\"{}\", .form_theme={}, .palette={}, .sprite_set={},\n\
        \x20     .starter_weapon={}, .signature_active={}, .passive_perk={},\n\
        \x20     .base_stats={{ {} }} }},\n",
        c.id.raw(), esc(c.name), form(c.form_theme), c.palette.raw(), c.sprite_set.raw(),
        c.starter_weapon.raw(), c.signature_active.raw(), c.passive_perk.raw(),
        emit_base_stats(c.base_stats),
    )
}

fn emit_base_stats(s: BaseStats) -> String {
    format!(".hp_max={}, .mp_max={}, .atk={}, .def={}, .spd={}",
        s.hp_max, s.mp_max, s.atk, s.def, s.spd)
}

// ---------------------------------------------------------------- items

fn write_items(out: &Path, reg: &Registry) -> Result<()> {
    let mut h = String::from(HEADER_NOTE);
    h.push_str(
        "#ifndef QUINTRA_GEN_ITEMS_H\n\
         #define QUINTRA_GEN_ITEMS_H\n\
         #include \"core/types.h\"\n\
         #include \"enums.h\"\n\
         \n\
         /* Effect: tagged record. kind = EFFECT_*; d0..d2 are kind-specific. */\n\
         typedef struct { u8 kind; u8 d0; u8 d1; u8 d2; } effect_t;\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u16             id;\n\
         \x20\x20\x20\x20const char*     name;\n\
         \x20\x20\x20\x20const char*     description;\n\
         \x20\x20\x20\x20u8              kind;       /* ITEM_KIND_* */\n\
         \x20\x20\x20\x20u8              p0;         /* kind payload */\n\
         \x20\x20\x20\x20u8              p1;\n\
         \x20\x20\x20\x20u8              p2;\n\
         \x20\x20\x20\x20u8              p3;\n\
         \x20\x20\x20\x20u8              icon_sprite;\n\
         \x20\x20\x20\x20u8              palette;\n\
         \x20\x20\x20\x20u8              rarity;\n\
         \x20\x20\x20\x20u8              n_effects;\n\
         \x20\x20\x20\x20const effect_t* effects;\n\
         } item_def_t;\n\
         \n",
    );
    h.push_str(&format!("#define N_ITEMS {}\n", reg.n_items()));
    h.push_str("extern const item_def_t items[];\n#endif\n");
    write_if_changed(out.join("items.h"), h)?;

    let mut b = String::from(HEADER_NOTE);
    b.push_str("#include \"items.h\"\n\n");
    // Emit per-item effects arrays (or NULL when empty)
    for item in &reg.items {
        if item.effects.is_empty() { continue; }
        b.push_str(&format!("static const effect_t _eff_item_{}[] = {{\n", item.id.raw()));
        for e in item.effects { b.push_str(&format!("    {},\n", emit_effect(e))); }
        b.push_str("};\n\n");
    }
    b.push_str("const item_def_t items[] = {\n");
    for item in &reg.items { b.push_str(&emit_item(item)); }
    b.push_str("};\n");
    write_if_changed(out.join("items.c"), b)?;
    Ok(())
}

fn emit_item(i: &Item) -> String {
    let (kind_tag, p0, p1, p2, p3) = match i.kind {
        ItemKind::Weapon { fire_rate, damage, projectile, mp_cost } =>
            ("ITEM_KIND_WEAPON", fire_rate, damage, proj_kind(projectile), mp_cost),
        ItemKind::Active { cooldown_rooms } =>
            ("ITEM_KIND_ACTIVE", cooldown_rooms, 0, 0, 0),
        ItemKind::Passive =>
            ("ITEM_KIND_PASSIVE", 0, 0, 0, 0),
        ItemKind::Consumable { uses } =>
            ("ITEM_KIND_CONSUMABLE", uses, 0, 0, 0),
    };
    let (n_eff, eff_ptr) = if i.effects.is_empty() {
        (0_usize, "(const effect_t*)0".to_string())
    } else {
        (i.effects.len(), format!("_eff_item_{}", i.id.raw()))
    };
    format!(
        "    {{ .id={}, .name=\"{}\", .description=\"{}\",\n\
        \x20     .kind={}, .p0={}, .p1={}, .p2={}, .p3={},\n\
        \x20     .icon_sprite={}, .palette={}, .rarity={},\n\
        \x20     .n_effects={}, .effects={} }},\n",
        i.id.raw(), esc(i.name), esc(i.description),
        kind_tag, p0, p1, p2, p3,
        i.icon_sprite.raw(), i.palette.raw(), rarity(i.rarity),
        n_eff, eff_ptr,
    )
}

fn emit_effect(e: &Effect) -> String {
    let (k, d0, d1, d2) = match *e {
        Effect::StatBoost { stat, delta } =>
            ("EFFECT_STAT_BOOST", stat_disc(stat), delta as u8, 0),
        Effect::OnHit(t)             => ("EFFECT_ON_HIT",          trig_disc(t), trig_d0(t), trig_d1(t)),
        Effect::OnRoomClear(t)       => ("EFFECT_ON_ROOM_CLEAR",   trig_disc(t), trig_d0(t), trig_d1(t)),
        Effect::OnPickup(t)          => ("EFFECT_ON_PICKUP",       trig_disc(t), trig_d0(t), trig_d1(t)),
        Effect::OnDamageTaken(t)     => ("EFFECT_ON_DAMAGE_TAKEN", trig_disc(t), trig_d0(t), trig_d1(t)),
        Effect::Dash { iframes, dist } => ("EFFECT_DASH", iframes, dist, 0),
        Effect::HealHearts(n)        => ("EFFECT_HEAL_HEARTS", n, 0, 0),
        Effect::GrantMp(n)           => ("EFFECT_GRANT_MP", n, 0, 0),
        Effect::RevealMap            => ("EFFECT_REVEAL_MAP", 0, 0, 0),
    };
    format!("{{ .kind={}, .d0={}, .d1={}, .d2={} }}", k, d0, d1, d2)
}

fn trig_disc(t: Trigger) -> u8 {
    match t {
        Trigger::SpawnProjectile { .. } => 0,
        Trigger::DealDamage     { .. }  => 1,
        Trigger::ApplyStatus    { .. }  => 2,
        Trigger::GiveCoins(_)           => 3,
    }
}
fn trig_d0(t: Trigger) -> u8 {
    match t {
        Trigger::SpawnProjectile { kind, .. } => proj_kind(kind),
        Trigger::DealDamage     { amount, .. } => amount,
        Trigger::ApplyStatus    { status, .. } => status_disc(status),
        Trigger::GiveCoins(n)                  => n,
    }
}
fn trig_d1(t: Trigger) -> u8 {
    match t {
        Trigger::SpawnProjectile { count, .. } => count,
        Trigger::DealDamage     { radius, .. } => radius,
        Trigger::ApplyStatus    { duration_ticks, .. } => duration_ticks,
        Trigger::GiveCoins(_) => 0,
    }
}

// ---------------------------------------------------------------- enemies

fn write_enemies(out: &Path, reg: &Registry) -> Result<()> {
    let mut h = String::from(HEADER_NOTE);
    h.push_str(
        "#ifndef QUINTRA_GEN_ENEMIES_H\n\
         #define QUINTRA_GEN_ENEMIES_H\n\
         #include \"core/types.h\"\n\
         #include \"enums.h\"\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u8 hp;\n\
         \x20\x20\x20\x20u8 damage;\n\
         \x20\x20\x20\x20u8 speed;\n\
         \x20\x20\x20\x20u8 score;\n\
         \x20\x20\x20\x20u8 weakness;\n\
         \x20\x20\x20\x20u8 poise;\n\
         } enemy_stats_t;\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u8            id;\n\
         \x20\x20\x20\x20const char*   name;\n\
         \x20\x20\x20\x20u8            sprite_set;\n\
         \x20\x20\x20\x20u8            palette;\n\
         \x20\x20\x20\x20enemy_stats_t stats;\n\
         \x20\x20\x20\x20u8            ai_kind;     /* AI_* */\n\
         \x20\x20\x20\x20u8            ai_p0;\n\
         \x20\x20\x20\x20u8            ai_p1;\n\
         \x20\x20\x20\x20u8            ai_p2;\n\
         \x20\x20\x20\x20u8            drop_table;\n\
         \x20\x20\x20\x20u8            n_biomes;\n\
         \x20\x20\x20\x20const u8*     biomes;\n\
         } enemy_def_t;\n\
         \n",
    );
    h.push_str(&format!("#define N_ENEMIES {}\n", reg.n_enemies()));
    h.push_str("extern const enemy_def_t enemies[];\n#endif\n");
    write_if_changed(out.join("enemies.h"), h)?;

    let mut b = String::from(HEADER_NOTE);
    b.push_str("#include \"enemies.h\"\n\n");
    for e in &reg.enemies {
        b.push_str(&format!("static const u8 _bio_enemy_{}[] = {{", e.id.raw()));
        for bi in e.biomes { b.push_str(&format!(" {},", bi.raw())); }
        b.push_str(" };\n");
    }
    b.push('\n');
    b.push_str("const enemy_def_t enemies[] = {\n");
    for e in &reg.enemies { b.push_str(&emit_enemy(e)); }
    b.push_str("};\n");
    write_if_changed(out.join("enemies.c"), b)?;
    Ok(())
}

fn emit_enemy(e: &Enemy) -> String {
    let (ak, p0, p1, p2) = match e.ai_script {
        AiScriptId::Walker  => ("AI_WALKER", 0, 0, 0),
        AiScriptId::Chaser  => ("AI_CHASER", 0, 0, 0),
        AiScriptId::Charger { telegraph_ticks, charge_speed } =>
            ("AI_CHARGER", telegraph_ticks, charge_speed, 0),
        AiScriptId::Shooter { fire_rate, projectile, pattern } => {
            let (pat_d, pat_n) = shot_pattern(pattern);
            ("AI_SHOOTER", fire_rate, proj_kind(projectile), pat_d | (pat_n << 4))
        },
        AiScriptId::Spinner { radius, fire_rate } =>
            ("AI_SPINNER", radius, fire_rate, 0),
        AiScriptId::Turret { rotation, fire_rate } =>
            ("AI_TURRET", rotation, fire_rate, 0),
        AiScriptId::SprayPattern { angles, fire_rate } =>
            ("AI_SPRAY", angles, fire_rate, 0),
        AiScriptId::AimedBurst { burst_size, recovery_ticks } =>
            ("AI_AIMEDBURST", burst_size, recovery_ticks, 0),
        AiScriptId::Teleporter { blink_rate, appear_dist } =>
            ("AI_TELEPORT", blink_rate, appear_dist, 0),
        AiScriptId::Replicator { open_ticks, closed_ticks } =>
            ("AI_REPLICATOR", open_ticks, closed_ticks, 0),
    };
    format!(
        "    {{ .id={}, .name=\"{}\", .sprite_set={}, .palette={},\n\
        \x20     .stats={{ {} }},\n\
        \x20     .ai_kind={}, .ai_p0={}, .ai_p1={}, .ai_p2={},\n\
        \x20     .drop_table={}, .n_biomes={}, .biomes=_bio_enemy_{} }},\n",
        e.id.raw(), esc(e.name), e.sprite_set.raw(), e.palette.raw(),
        emit_enemy_stats(e.stats),
        ak, p0, p1, p2,
        e.drop_table.raw(), e.biomes.len(), e.id.raw(),
    )
}

fn emit_enemy_stats(s: EnemyStats) -> String {
    format!(".hp={}, .damage={}, .speed={}, .score={}, .weakness={}, .poise={}",
        s.hp, s.damage, s.speed, s.score, s.weakness, s.poise)
}

fn shot_pattern(p: ShotPattern) -> (u8, u8) {
    match p {
        ShotPattern::Single        => (0, 0),
        ShotPattern::Fan(n)        => (1, n),
        ShotPattern::Ring(n)       => (2, n),
        ShotPattern::Burst(n)      => (3, n),
        ShotPattern::Spiral { steps } => (4, steps),
    }
}

// ---------------------------------------------------------------- biomes

fn write_biomes(out: &Path, reg: &Registry) -> Result<()> {
    let mut h = String::from(HEADER_NOTE);
    h.push_str(
        "#ifndef QUINTRA_GEN_BIOMES_H\n\
         #define QUINTRA_GEN_BIOMES_H\n\
         #include \"core/types.h\"\n\
         #include \"enums.h\"\n\
         \n\
         typedef struct { u8 enemy_id; u8 weight; } enemy_pool_entry_t;\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u8           id;\n\
         \x20\x20\x20\x20const char*  name;\n\
         \x20\x20\x20\x20u8           depth_min;\n\
         \x20\x20\x20\x20u8           depth_max;\n\
         \x20\x20\x20\x20u8           tileset;\n\
         \x20\x20\x20\x20u8           bg_pal[4];\n\
         \x20\x20\x20\x20u8           music_track;\n\
         \x20\x20\x20\x20u8           n_enemy_pool;\n\
         \x20\x20\x20\x20const enemy_pool_entry_t* enemy_pool;\n\
         \x20\x20\x20\x20u8           n_rooms_pool;\n\
         \x20\x20\x20\x20const u16*   room_pool;\n\
         \x20\x20\x20\x20u8           min_rooms;\n\
         \x20\x20\x20\x20u8           max_rooms;\n\
         \x20\x20\x20\x20u8           has_shop;\n\
         \x20\x20\x20\x20u8           has_altar;\n\
         \x20\x20\x20\x20u8           boss;\n\
         } biome_def_t;\n\
         \n",
    );
    h.push_str(&format!("#define N_BIOMES {}\n", reg.n_biomes()));
    h.push_str("extern const biome_def_t biomes[];\n#endif\n");
    write_if_changed(out.join("biomes.h"), h)?;

    let mut b = String::from(HEADER_NOTE);
    b.push_str("#include \"biomes.h\"\n\n");
    for bi in &reg.biomes {
        b.push_str(&format!("static const enemy_pool_entry_t _epool_biome_{}[] = {{\n", bi.id.raw()));
        for (eid, w) in bi.enemy_pool {
            b.push_str(&format!("    {{ {}, {} }},\n", eid.raw(), w));
        }
        b.push_str("};\n");

        b.push_str(&format!("static const u16 _rpool_biome_{}[] = {{", bi.id.raw()));
        for tid in bi.room_template_pool {
            b.push_str(&format!(" {},", tid.raw()));
        }
        b.push_str(" };\n\n");
    }

    b.push_str("const biome_def_t biomes[] = {\n");
    for bi in &reg.biomes { b.push_str(&emit_biome(bi)); }
    b.push_str("};\n");
    write_if_changed(out.join("biomes.c"), b)?;
    Ok(())
}

fn emit_biome(b: &quintra_content::Biome) -> String {
    format!(
        "    {{ .id={}, .name=\"{}\", .depth_min={}, .depth_max={},\n\
        \x20     .tileset={}, .bg_pal={{ {},{},{},{} }}, .music_track={},\n\
        \x20     .n_enemy_pool={}, .enemy_pool=_epool_biome_{},\n\
        \x20     .n_rooms_pool={}, .room_pool=_rpool_biome_{},\n\
        \x20     .min_rooms={}, .max_rooms={},\n\
        \x20     .has_shop={}, .has_altar={}, .boss={} }},\n",
        b.id.raw(), esc(b.name), b.depth_range.0, b.depth_range.1,
        b.tileset.raw(),
        b.bg_palettes[0].raw(), b.bg_palettes[1].raw(),
        b.bg_palettes[2].raw(), b.bg_palettes[3].raw(),
        b.music_track.raw(),
        b.enemy_pool.len(), b.id.raw(),
        b.room_template_pool.len(), b.id.raw(),
        b.min_rooms, b.max_rooms,
        b.has_shop as u8, b.has_altar as u8, b.boss.raw(),
    )
}

// ---------------------------------------------------------------- rooms

fn write_rooms(out: &Path, reg: &Registry) -> Result<()> {
    let mut h = String::from(HEADER_NOTE);
    h.push_str(
        "#ifndef QUINTRA_GEN_ROOMS_H\n\
         #define QUINTRA_GEN_ROOMS_H\n\
         #include \"core/types.h\"\n\
         #include \"enums.h\"\n\
         \n\
         typedef struct { u8 x; u8 y; u8 role; } spawn_slot_t;\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u16          id;\n\
         \x20\x20\x20\x20u8           size;       /* ROOM_* */\n\
         \x20\x20\x20\x20u16          layout;     /* tilemap blob id */\n\
         \x20\x20\x20\x20u8           doors;      /* DOOR_* bitmask */\n\
         \x20\x20\x20\x20u8           kind;       /* ROOMKIND_* */\n\
         \x20\x20\x20\x20u8           n_slots;\n\
         \x20\x20\x20\x20const spawn_slot_t* slots;\n\
         } room_tpl_t;\n\
         \n",
    );
    h.push_str(&format!("#define N_ROOM_TEMPLATES {}\n", reg.n_room_templates()));
    h.push_str("extern const room_tpl_t room_templates[];\n#endif\n");
    write_if_changed(out.join("rooms.h"), h)?;

    let mut b = String::from(HEADER_NOTE);
    b.push_str("#include \"rooms.h\"\n\n");
    for r in &reg.room_templates {
        if r.spawn_slots.is_empty() { continue; }
        b.push_str(&format!("static const spawn_slot_t _slots_room_{}[] = {{\n", r.id.raw()));
        for s in r.spawn_slots {
            b.push_str(&format!("    {{ {}, {}, {} }},\n", s.x, s.y, spawn_role(s.role)));
        }
        b.push_str("};\n\n");
    }
    b.push_str("const room_tpl_t room_templates[] = {\n");
    for r in &reg.room_templates { b.push_str(&emit_room(r)); }
    b.push_str("};\n");
    write_if_changed(out.join("rooms.c"), b)?;
    Ok(())
}

fn emit_room(r: &RoomTemplate) -> String {
    let (n, slots) = if r.spawn_slots.is_empty() {
        (0_usize, "(const spawn_slot_t*)0".to_string())
    } else {
        (r.spawn_slots.len(), format!("_slots_room_{}", r.id.raw()))
    };
    format!(
        "    {{ .id={}, .size={}, .layout={}, .doors={}, .kind={}, .n_slots={}, .slots={} }},\n",
        r.id.raw(),
        match r.size {
            RoomSize::Small  => "ROOM_SMALL",
            RoomSize::Medium => "ROOM_MEDIUM",
            RoomSize::Large  => "ROOM_LARGE",
        },
        r.layout.raw(),
        r.doors.raw(),
        match r.kind {
            RoomKind::Combat   => "ROOMKIND_COMBAT",
            RoomKind::Treasure => "ROOMKIND_TREASURE",
            RoomKind::Shop     => "ROOMKIND_SHOP",
            RoomKind::Altar    => "ROOMKIND_ALTAR",
            RoomKind::Puzzle   => "ROOMKIND_PUZZLE",
            RoomKind::Boss     => "ROOMKIND_BOSS",
        },
        n, slots,
    )
}

// ---------------------------------------------------------------- zelda overworld

fn write_zelda_overworld(out: &Path, reg: &Registry) -> Result<()> {
    let mut h = String::from(HEADER_NOTE);
    h.push_str(
        "#ifndef QUINTRA_GEN_ZELDA_OVERWORLD_H\n\
         #define QUINTRA_GEN_ZELDA_OVERWORLD_H\n\
         #include \"core/types.h\"\n\
         #include \"enums.h\"\n\
         \n\
         #define ZELDA_CELL_OVERWORLD       0\n\
         #define ZELDA_CELL_CAVE_ENTRANCE   1\n\
         #define ZELDA_CELL_DUNGEON_ENTRANCE 2\n\
         #define ZELDA_CELL_VAULT           3\n\
         #define ZELDA_CELL_BOSS            4\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20u8 kind;\n\
         \x20\x20\x20\x20u8 edges;\n\
         \x20\x20\x20\x20u16 room_tpl;\n\
         \x20\x20\x20\x20screen_id_t secret;\n\
         \x20\x20\x20\x20screen_id_t stairs;\n\
         } zelda_screen_t;\n\
         \n\
         typedef struct {\n\
         \x20\x20\x20\x20biome_id_t id;\n\
         \x20\x20\x20\x20const char* name;\n\
         \x20\x20\x20\x20const zelda_screen_t* screen_grid;\n\
         } zelda_overworld_def_t;\n\
         \n",
    );
    h.push_str(&format!("#define N_ZELDA_OVERWORLDS {}\n", reg.n_zelda_overworlds()));
    h.push_str("extern const zelda_overworld_def_t zelda_overworlds[];\n#endif\n");
    write_if_changed(out.join("zelda_overworld.h"), h)?;

    let mut c = String::from(HEADER_NOTE);
    c.push_str("#include \"zelda_overworld.h\"\n\n");
    for z in &reg.zelda_overworlds {
        c.push_str(&format!("static const zelda_screen_t _zelda_grid_{}[16] = {{\n", z.id.raw()));
        for idx in 0..16 {
            c.push_str(&format!("    {},\n", emit_zelda_screen(z, idx)));
        }
        c.push_str("};\n\n");
    }
    c.push_str("const zelda_overworld_def_t zelda_overworlds[] = {\n");
    for z in &reg.zelda_overworlds {
        c.push_str(&format!(
            "    {{ .id={}, .name=\"{}\", .screen_grid=_zelda_grid_{} }},\n",
            z.id.raw(),
            esc(z.name),
            z.id.raw(),
        ));
    }
    c.push_str("};\n");
    write_if_changed(out.join("zelda_overworld.c"), c)?;
    Ok(())
}

fn emit_zelda_screen(z: &ZeldaOverworldBiome, idx: usize) -> String {
    let cell = z.cell(idx);
    format!(
        "{{ .kind={}, .edges={}, .room_tpl={}, .secret={}, .stairs={} }}",
        zelda_cell_kind(cell.cell_kind),
        cell.edges.raw(),
        cell.room_tpl_id.raw(),
        opt_screen_id(cell.secret_to),
        opt_screen_id(cell.staircase_to),
    )
}

