// ---------------------------------------------------------------- stages

fn emit_pal4(p: &[quintra_content::Rgb5; 4]) -> String {
    format!("{{ 0x{:04X}, 0x{:04X}, 0x{:04X}, 0x{:04X} }}",
        p[0].to_bgr555(), p[1].to_bgr555(), p[2].to_bgr555(), p[3].to_bgr555())
}

fn write_stages(out: &Path, reg: &Registry) -> Result<()> {
    let n = reg.stages.len();

    let h = format!(
        "{HEADER_NOTE}\
         #ifndef QUINTRA_GEN_STAGES_H\n\
         #define QUINTRA_GEN_STAGES_H\n\
         #include \"core/types.h\"\n\
         \n\
         #define N_STAGES {n}\n\
         \n\
         /* [stage][floor|wall|crystal|door][color 0-3], BGR555 */\n\
         extern const u16 stage_pal[N_STAGES][4][4];\n\
         /* Large-boss OBJ tint per stage: [_, rim, body-dark, glow] */\n\
         extern const u16 boss_stage_pal[N_STAGES][4];\n\
         /* Cracked-wall palette — constant across stages */\n\
         extern const u16 stage_pal_crack[4];\n\
         /* Display names (PACK screen) */\n\
         extern const char *const stage_names[N_STAGES];\n\
         /* Large-boss stat bonuses per stage (indexed by CLAMPED stage) */\n\
         extern const u8 stage_boss_hp[N_STAGES];\n\
         extern const u8 stage_boss_dmg[N_STAGES];\n\
         /* Mini-boss silhouette per stage: 0 Sentinel, 1 Orc, 2 Skeleton.\n\
            Single source for BOTH the art loader and the palette pick. */\n\
         extern const u8 stage_mb_variant[N_STAGES];\n\
         /* Weighted normal-room rosters per stage (ids + weights,\n\
            stage_pool_n entries each; weights sum <= 255) */\n\
         #define STAGE_POOL_MAX 4\n\
         extern const u8 stage_pool_ids[N_STAGES][STAGE_POOL_MAX];\n\
         extern const u8 stage_pool_w[N_STAGES][STAGE_POOL_MAX];\n\
         extern const u8 stage_pool_n[N_STAGES];\n\
         extern const u8 stage_pool_total[N_STAGES];\n\
         #endif\n");
    write_if_changed(out.join("stages.h"), h).context("write stages.h")?;

    let mut c = String::from(HEADER_NOTE);
    c.push_str("#include \"stages.h\"\n\n");

    c.push_str(&format!("const u16 stage_pal[N_STAGES][4][4] = {{\n"));
    for s in &reg.stages {
        c.push_str(&format!("    /* {} — {} */\n    {{\n", s.id, esc(s.name)));
        for pal in [&s.floor, &s.wall, &s.crystal, &s.door] {
            c.push_str(&format!("        {},\n", emit_pal4(pal)));
        }
        c.push_str("    },\n");
    }
    c.push_str("};\n\n");

    c.push_str("const u16 boss_stage_pal[N_STAGES][4] = {\n");
    for s in &reg.stages {
        c.push_str(&format!("    {},   /* {} */\n", emit_pal4(&s.boss), esc(s.name)));
    }
    c.push_str("};\n\n");

    let crack = quintra_game_content::stages::CRACK_PAL;
    c.push_str(&format!("const u16 stage_pal_crack[4] = {};\n\n", emit_pal4(&crack)));

    c.push_str("const char *const stage_names[N_STAGES] = {\n");
    for s in &reg.stages {
        c.push_str(&format!("    \"{}\",\n", esc(s.name)));
    }
    c.push_str("};\n\n");

    let list = |f: &dyn Fn(&quintra_content::StageTheme) -> u8| {
        reg.stages.iter().map(|s| f(s).to_string()).collect::<Vec<_>>().join(", ")
    };
    c.push_str(&format!("const u8 stage_boss_hp[N_STAGES] = {{ {} }};\n",
        list(&|s| s.boss_hp_bonus)));
    c.push_str(&format!("const u8 stage_boss_dmg[N_STAGES] = {{ {} }};\n",
        list(&|s| s.boss_dmg_bonus)));
    c.push_str(&format!("const u8 stage_mb_variant[N_STAGES] = {{ {} }};\n",
        list(&|s| s.mb_variant)));

    c.push_str("\nconst u8 stage_pool_ids[N_STAGES][STAGE_POOL_MAX] = {\n");
    for s in &reg.stages {
        let mut ids = [0u8; 4];
        for (i, &(eid, _)) in s.enemy_pool.iter().enumerate() { ids[i] = eid; }
        c.push_str(&format!("    {{ {}, {}, {}, {} }},\n", ids[0], ids[1], ids[2], ids[3]));
    }
    c.push_str("};\n");
    c.push_str("const u8 stage_pool_w[N_STAGES][STAGE_POOL_MAX] = {\n");
    for s in &reg.stages {
        let mut ws = [0u8; 4];
        for (i, &(_, w)) in s.enemy_pool.iter().enumerate() { ws[i] = w; }
        c.push_str(&format!("    {{ {}, {}, {}, {} }},\n", ws[0], ws[1], ws[2], ws[3]));
    }
    c.push_str("};\n");
    c.push_str(&format!("const u8 stage_pool_n[N_STAGES] = {{ {} }};\n",
        list(&|s| s.enemy_pool.len() as u8)));
    c.push_str(&format!("const u8 stage_pool_total[N_STAGES] = {{ {} }};\n",
        list(&|s| s.enemy_pool.iter().map(|&(_, w)| w).sum::<u8>())));

    write_if_changed(out.join("stages.c"), c).context("write stages.c")?;
    let _ = n;
    Ok(())
}

// ---------------------------------------------------------------- helpers

/// Replace a generated file only when its bytes changed. Besides avoiding
/// needless disk churn, preserving the mtime is part of the build contract:
/// all cartridge objects conservatively depend on all generated headers.
fn write_if_changed(path: PathBuf, contents: impl AsRef<[u8]>) -> Result<bool> {
    let contents = contents.as_ref();
    if fs::read(&path).map(|current| current == contents).unwrap_or(false) {
        return Ok(false);
    }
    fs::write(&path, contents).with_context(|| format!("write {}", path.display()))?;
    Ok(true)
}

fn esc(s: &str) -> String {
    s.chars().flat_map(|c| match c {
        '"' => "\\\"".chars().collect::<Vec<_>>(),
        '\\' => "\\\\".chars().collect(),
        '\n' => "\\n".chars().collect(),
        c if (c as u32) < 0x20 => format!("\\x{:02x}", c as u32).chars().collect(),
        c => vec![c],
    }).collect()
}

fn form(f: FormTheme) -> &'static str {
    match f {
        FormTheme::Wolfkin => "FORM_WOLFKIN",
        FormTheme::Sauran  => "FORM_SAURAN",
        FormTheme::Corvin  => "FORM_CORVIN",
        FormTheme::Picsean => "FORM_PICSEAN",
        FormTheme::Vespine => "FORM_VESPINE",
    }
}

fn rarity(r: Rarity) -> &'static str {
    match r {
        Rarity::Common   => "RARITY_COMMON",
        Rarity::Uncommon => "RARITY_UNCOMMON",
        Rarity::Rare     => "RARITY_RARE",
        Rarity::Boss     => "RARITY_BOSS",
    }
}

fn proj_kind(p: ProjectileKind) -> u8 {
    match p {
        ProjectileKind::Bullet    => 0,
        ProjectileKind::Bolt      => 1,
        ProjectileKind::Homing    => 2,
        ProjectileKind::Wave      => 3,
        ProjectileKind::Spread3   => 4,
        ProjectileKind::Spread5   => 5,
        ProjectileKind::Boomerang => 6,
        ProjectileKind::Bomb      => 7,
        ProjectileKind::Laser     => 8,
        ProjectileKind::Bubble    => 9,
        ProjectileKind::Spike     => 10,
        ProjectileKind::Shuriken  => 11,
    }
}

fn status_disc(s: Status) -> u8 {
    match s {
        Status::None     => 0,
        Status::Burning  => 1,
        Status::Frozen   => 2,
        Status::Poisoned => 3,
        Status::Stunned  => 4,
        Status::Cursed   => 5,
        Status::Marked   => 6,
    }
}

fn zelda_cell_kind(kind: ScreenCellKind) -> &'static str {
    match kind {
        ScreenCellKind::Overworld => "ZELDA_CELL_OVERWORLD",
        ScreenCellKind::CaveEntrance => "ZELDA_CELL_CAVE_ENTRANCE",
        ScreenCellKind::DungeonEntrance => "ZELDA_CELL_DUNGEON_ENTRANCE",
        ScreenCellKind::Vault => "ZELDA_CELL_VAULT",
        ScreenCellKind::Boss => "ZELDA_CELL_BOSS",
    }
}

fn opt_screen_id(id: Option<u8>) -> String {
    match id {
        Some(id) => id.to_string(),
        None => "ID_NONE_U8".to_string(),
    }
}

fn stat_disc(s: Stat) -> u8 {
    match s {
        Stat::Hp  => 0,
        Stat::Mp  => 1,
        Stat::Atk => 2,
        Stat::Def => 3,
        Stat::Spd => 4,
        Stat::Lck => 5,
    }
}

fn spawn_role(r: SpawnRole) -> &'static str {
    match r {
        SpawnRole::Enemy      => "SPAWN_ENEMY",
        SpawnRole::Pickup     => "SPAWN_PICKUP",
        SpawnRole::Hazard     => "SPAWN_HAZARD",
        SpawnRole::Decoration => "SPAWN_DECORATION",
    }
}

#[allow(dead_code)]
fn door_mask(d: DoorMask) -> u8 { d.raw() }

#[allow(dead_code)]
fn spawn_slot(s: SpawnSlot) -> String {
    format!("{}, {}, {}", s.x, s.y, spawn_role(s.role))
}

#[cfg(test)]
mod tests {
    use super::write_if_changed;
    use std::fs;

    #[test]
    fn unchanged_output_is_not_rewritten() {
        let path = std::env::temp_dir().join(format!(
            "quintra-codegen-idempotent-{}-{}",
            std::process::id(),
            std::thread::current().name().unwrap_or("test")
        ));
        let _ = fs::remove_file(&path);
        assert!(write_if_changed(path.clone(), b"first").unwrap());
        assert!(!write_if_changed(path.clone(), b"first").unwrap());
        assert!(write_if_changed(path.clone(), b"second").unwrap());
        assert_eq!(fs::read(&path).unwrap(), b"second");
        let _ = fs::remove_file(path);
    }
}
